import { useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { fetchPayPalUserInfo, setPayPalAuthStatus, PayPalAuthStatus } from "@/utils/cashoutPaypal";
import { useUser } from "@/hooks/useUser";
import { useCashout } from "@/hooks/useCashout";
import { showCashoutModal } from "@/components/showCashoutModal";
import { CashOutStatus, stageAmountMap, USPaypalAccountType } from "@/types/cashout";
import { STORAGE_KEYS } from "@/constants/storageKeys";
import { normalMediumWithdrawCheck } from "@/http/cashoutApi";
import { getUserCountryCode } from "@/utils/locationUtils";
import { UserServiceCommonCode } from "@sitin/api-proto/gen/archat_api/user_api";
import { toast } from "@/utils/toast";
import Spinner from "@/components/Spinner";

export default function PayPalResultPage() {
  const navigate = useNavigate();
  const { paypalAccount, logout } = useUser();
  const { willCashoutStage } = useCashout();
  const hasHandled = useRef(false);
  const willCashoutStageRef = useRef(willCashoutStage);
  const logoutRef = useRef(logout);

  useEffect(() => {
    willCashoutStageRef.current = willCashoutStage;
    logoutRef.current = logout;
  });

  useEffect(() => {
    const navigateBack = () => {
      const stackLength = localStorage.getItem(STORAGE_KEYS.PAYPAL_OAUTH_HISTORY_LENGTH);
      if (stackLength) {
        const targetLength = Number(stackLength);
        window.history.go(-(window.history.length - targetLength));
      } else {
        navigate("/");
      }
    };

    const handlePayPalCallback = async () => {
      try {
        const userInfo = await fetchPayPalUserInfo();

        if (!userInfo || !userInfo.email) {
          console.error("PayPal OAuth: failed to fetch user info", {
            hasCode: !!new URLSearchParams(window.location.search).get("code"),
          });
          localStorage.removeItem(STORAGE_KEYS.CASHOUT_FLOW_PENDING);
          toast.error("Failed to connect PayPal. Please try again.");
          await setPayPalAuthStatus(PayPalAuthStatus.Error);
          navigateBack();
          return;
        }

        const country = userInfo.address?.country || "";

        // 保存 PayPal 账户来源国家
        if (country === "US") {
          localStorage.setItem(STORAGE_KEYS.PAYPAL_COUNTRY_IS_US, "true");
        } else {
          localStorage.setItem(STORAGE_KEYS.PAYPAL_COUNTRY_IS_US, "false");
        }

        // 调用 ban 检查接口（无感操作）
        try {
          // 获取 GPS 位置
          const gpsCountryCode = await getUserCountryCode();
          const isLbsAmerica = gpsCountryCode === "us";

          // 获取 PayPal 账户类型
          let usPaypalAccountType = USPaypalAccountType.US_PAYPAL_UNKNOWN;
          if (country === "US") {
            usPaypalAccountType = USPaypalAccountType.US_PAYPAL_ACCOUNT;
          } else if (country && country !== "US") {
            usPaypalAccountType = USPaypalAccountType.NON_US_PAYPAL_ACCOUNT;
          }

          // 调用检查接口，后端会根据参数判断是否 ban 用户
          const checkResponse = await normalMediumWithdrawCheck({
            isLbsAmerica,
            usPaypalAccountType,
          });

          // 如果用户被 ban，清除登录信息并跳转到登录页
          if (checkResponse.code === UserServiceCommonCode.USER_BANNED) {
            console.log("User has been banned, logging out...");
            logoutRef.current();
            window.location.href = "/onboarding";
            return;
          }
        } catch (error) {
          // 静默处理错误，不影响用户继续流程
          console.error("Failed to check withdraw status:", error);
        }

        // 验证 PayPal 账户
        if (
          paypalAccount &&
          userInfo.email.trim().toLowerCase() === paypalAccount.trim().toLowerCase() &&
          (!country || country === "US")
        ) {
          await setPayPalAuthStatus(PayPalAuthStatus.Success);
        } else {
          await setPayPalAuthStatus(PayPalAuthStatus.Failed);
          const emailMatch = userInfo.email.trim().toLowerCase() === paypalAccount?.trim().toLowerCase();
          const countryOk = !country || country === "US";
          console.error("PayPal verification failed:", {
            oauthEmail: userInfo.email,
            boundEmail: paypalAccount,
            country,
            emailMatch,
            countryOk,
            hasPaypalAccount: !!paypalAccount,
          });
        }

        // 检查是否有待继续的提现流程
        const hasPendingCashout = localStorage.getItem(STORAGE_KEYS.CASHOUT_FLOW_PENDING);
        navigateBack();
        // 如果存在待继续的提现流程，自动打开提现弹窗
        if (hasPendingCashout) {
          localStorage.removeItem(STORAGE_KEYS.CASHOUT_FLOW_PENDING);
          // 根据当前提现阶段获取金额
          const cashoutAmount = stageAmountMap[willCashoutStageRef.current];
          // 延迟打开弹窗，确保导航完成
          setTimeout(() => {
            showCashoutModal({
              initialStatus: CashOutStatus.PAYPAL_BIND_RESULT,
              amount: cashoutAmount.toFixed(2),
            });
          }, 500);
        }
      } catch (error) {
        console.error("Failed to handle PayPal callback:", error);
        localStorage.removeItem(STORAGE_KEYS.CASHOUT_FLOW_PENDING);
        toast.error("Failed to connect PayPal. Please try again.");
        await setPayPalAuthStatus(PayPalAuthStatus.Error);
        navigate("/");
      }
    };

    if (paypalAccount && !hasHandled.current) {
      hasHandled.current = true;
      handlePayPalCallback();
    }
  }, [paypalAccount, navigate]);

  return (
    <div className="flex items-center justify-center h-full w-full fixed inset-0 bg-surface">
      <div className="flex flex-col items-center gap-4">
        <Spinner size={48} />
        <p className="text-[15px] text-gray-500 text-center px-6">Processing PayPal authentication...</p>
      </div>
    </div>
  );
}
